	}
	if _, ok := validFields[groupByField]; !ok {
		return nil, errors.New("invalid groupByField")
	}

	var results []map[string]interface{}

	// Construct the query
	// SELECT u.[groupByField] as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
	// FROM user_profile u
	// LEFT JOIN user_activity a ON u.id = a.user_id
	// WHERE u.department IN (?, ?, ...)
	// GROUP BY u.[groupByField]

