// repeatParams generates a string of ", ?" repeated n times
func repeatParams(n int) string {
	if n <= 0 {
		return ""
	}
	b := make([]byte, n*2)
	for i := 0; i < n; i++ {
		b[i*2] = ','
		b[i*2+1] = '?'
	}
	return string(b)
}

